      const newProduct = {
        id: productUniqueId, // Incorporate color into ID for uniqueness
        name: product.name,
        amount: amount,
        image: product.image,
        price: product.price
      };
      return {...state, cart: [...state.cart, newProduct]};
    }
  }
  // Handle other action types...
};
```

